import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — base premiums and processing fee
  it.todo("empty item list yields premium of 5 G (only the processing fee)");
  it.todo("quote for a single plain sword (steel, enchantment 3) yields 105 G");
  it.todo("quote for a single plain amulet yields 65 G");
  it.todo("quote for a single plain staff yields 85 G");
  it.todo("quote for a single plain potion yields 45 G");

  // Components and blocks
  it.todo("quote for 2 runes yields 55 G (no block)");
  it.todo("quote for 3 runes applies block, yielding 65 G");
  it.todo("quote for 4 runes yields 105 G (no block, block requires exactly 3)");
  it.todo("quote for 7 runes yields 180 G (no block)");
  it.todo("quote for 2 runes + 1 moonstone yields 80 G (no block, different types)");
  it.todo("quote for 3 runes + 3 moonstones applies two blocks, yielding 125 G");

  // Item-specific modifiers
  it.todo("cursed sword adds 50% surcharge on the item's base premium");
  it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 stacks both surcharges");

  // Policy-wide modifiers
  it.todo("customer with exactly 2 years applies 20% loyalty discount");
  it.todo("first insurance adds 10% initial assessment surcharge");
  it.todo("follow-up contract applies 15% discount on contracts after the first");

  // Multi-item modifier scope
  it.todo("cursed surcharge applies only to the cursed item, not to whole policy");

  // Rounding
  it.todo("premium is rounded up to whole G (MHPCO's favor)");

  // Integration examples
  it.todo("newcomer with cursed sword yields 165 G");
  it.todo("long-standing customer's second contract with cursed enchanted sword yields 160 G");

  // Claim — basic processing
  it.todo("claim on a regular sword with 500 G damage yields payout 400 G after deductible");
  it.todo("claim on a rune with 200 G damage yields payout 100 G after deductible");
  it.todo("claim on enchantment-9 sword (steel) with 1000 G damage yields payout 400 G");
  it.todo("claim on a dragon-material sword with 800 G damage yields full payout 700 G");
  it.todo("dragon-material sword with enchantment 9 and 1000 G damage yields payout 400 G");

  // Deductible per damage event
  it.todo("multiple damaged items each incur their own deductible");

  // Cap
  it.todo("payout is capped at twice the insurance sum across successive claims");
  it.todo("claim references unknown item rejects the claim");

  // CLI errors
  it.todo("quote with unknown item type rejects the quote");
  it.todo("claim with negative damage amount is rejected");
});

